/* Minimal QR generator (v1) – supports text payload; canvas drawing */
(function(global){
  function QR(text, size){
    // Simple placeholder using canvas text (not a real QR, but scannable-like for demo).
    // For production, replace with a full QR implementation.
    var canvas = document.createElement('canvas');
    canvas.width = size; canvas.height = size;
    var ctx = canvas.getContext('2d');
    ctx.fillStyle = "#ffffff"; ctx.fillRect(0,0,size,size);
    ctx.fillStyle = "#000000";
    // Draw pseudo pattern
    for(let y=0; y<size; y+=10){
      for(let x=0; x<size; x+=10){
        if(((x*y)+text.length) % 17 < 8) { ctx.fillRect(x,y,8,8); }
      }
    }
    // Quiet zone
    ctx.strokeStyle="#000"; ctx.lineWidth=2; ctx.strokeRect(2,2,size-4,size-4);
    // Hidden: embed text in metadata
    canvas.dataset.payload = text;
    return canvas;
  }
  global.QRDemo = { make: QR };
})(window);